// Lấy items từ node Merge
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { error: "Không có dữ liệu" } }];
}

const resultItems = [];

// Duyệt qua từng item
for (const item of items) {
  const json = item.json;
  const name = json.name || "";
  const mimeType = json.mimeType || "";

  // 1. Filter: Bỏ qua folders
  if (mimeType.includes('folder')) continue;

  // 2. Filter: Chỉ lấy PDF/DOC/DOCX
  if (!/\.(pdf|doc|docx)$/i.test(name)) continue;

  // 3. Parse Metadata
  let parsedData = {};

  // Regex format MỚI: [Date] - [Pos] (Code_ID) - [Source] - [Skills] - [File].ext
  const newRegex = /^(.+?)\s*-\s*(.+?)\s*\(([^_]+)_([^)]+)\)\s*-\s*(.+?)\s*-\s*(.+?)\s*-\s*(.+?)\.(pdf|doc|docx)$/i;
  const newMatch = name.match(newRegex);

  if (newMatch) {
    const [, date, pos, code, id, src, skill, fname] = newMatch;
    parsedData = {
      col_1: date.trim(),
      col_2: pos.trim(),
      col_3: src.trim(),
      job_code: code.trim(),
      position_id: id.trim(),
      skills: skill.trim(),
      fullname: fname.trim(),
      original_filename: name
    };
  } else {
    // Fallback: Format cũ (không có Skills)
    const oldRegex = /^(.+?)\s*-\s*(.+?)\s*\(([^_]+)_([^)]+)\)\s*-\s*(.+?)\s*-\s*(.+?)\.(pdf|doc|docx)$/i;
    const oldMatch = name.match(oldRegex);

    if (oldMatch) {
      const [, date, pos, code, id, src, fname] = oldMatch;
      parsedData = {
        col_1: date.trim(),
        col_2: pos.trim(),
        col_3: src.trim(),
        job_code: code.trim(),
        position_id: id.trim(),
        skills: "N/A",
        fullname: fname.trim(),
        original_filename: name
      };
    } else {
      // Fallback cuối cùng: giữ nguyên file nhưng đánh dấu lỗi format
      // Quan trọng: Vẫn parse để không mất file từ Store Trigger
      parsedData = {
        error: `Format sai: ${name}`,
        col_1: new Date().toLocaleDateString("en-GB"),
        col_2: "Unknown",
        col_3: json.source_origin || "Drive", // Lấy từ Tag Source
        skills: "N/A",
        fullname: name,
        original_filename: name
      };
    }
  }

  // 4. Return item (Giữ lại source_group & id để routing/download)
  resultItems.push({
    json: {
      ...json, // Giữ id, source_group, webViewLink...
      ...parsedData
    }
  });
}

if (resultItems.length === 0) {
    return [{ json: { error: "Không tìm thấy file CV hợp lệ nào" } }];
}

return resultItems;

// Lấy tất cả items từ Merge Node
const items = $input.all();

const toTitleCase = (str) => {
  if (!str) return "";
  return str.toLowerCase().split(" ").map(word => word.charAt(0).toUpperCase() + word.slice(1)).join(" ");
};

const parseNumber = (value) => {
  if (!value) return null;
  const cleaned = String(value).replace(/[^0-9.,-]/g, "").replace(",", ".");
  const num = parseFloat(cleaned);
  return isNaN(num) ? null : num;
};

// === FIX: HÀM CLEAN HTML & FORMAT LIST ===
const cleanAndFormatList = (text) => {
  if (!text) return "";

  // 1. Remove HTML tags (<ul>, <li>, etc.)
  let cleanText = text
    .replace(/<\/li>/g, "\n")      // </li> -> xuống dòng
    .replace(/<[^>]*>/g, "")       // Xóa tất cả thẻ <...> còn lại
    .replace(/&amp;/g, "&")        // Decode entities cơ bản
    .replace(/&nbsp;/g, " ");

  // 2. Format Bullet Points
  cleanText = cleanText.replace(/^[•\-\*]\s*/gm, '').trim(); // Xóa bullet cũ

  // 3. Split sentences & Re-add bullets
  const sentences = cleanText.split(/\.\s+|\n+/).map(s => s.trim()).filter(s => s.length > 2);

  if (sentences.length === 0) return "";
  if (sentences.length === 1) return `- ${sentences[0]}`;

  return sentences.map(s => `- ${s}${s.endsWith('.') ? '' : '.'}`).join('\n');
};

const cleanJobTitle = (rawTitle) => {
  if (!rawTitle) return "Unspecified";
  let clean = rawTitle.split("(")[0];
  clean = clean.split(/[-–—_]|(\s(tại|khu vực|có|with|in|at|fmcg|kỹ năng)\s)/i)[0].trim();
  clean = clean.replace(/[^a-zA-Z0-9àáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđ\s]+$/, "");
  return toTitleCase(clean);
};

// HELPER: Tìm data (Ưu tiên lấy từ $json truyền xuống từ Merge/Set)
const findData = (key, itemJson) => {
  // 1. Ưu tiên lấy trực tiếp từ item hiện tại (đã được merge/set từ trước)
  if (itemJson[key]) return itemJson[key];
  if (itemJson[`col_${key}`]) return itemJson[`col_${key}`]; // Fallback cho col_1, col_2...

  // 2. Fallback tham chiếu ngược (chỉ khi cần thiết & node đã chạy)
  try {
    if ($('Code').isExecuted) {
      const val = $('Code').first().json[key];
      if (val) return val;
    }
  } catch(e) {}

  try {
    if ($('Profile Wanted').isExecuted) {
      const val = $('Profile Wanted').first().json[key];
      if (val) return val;
    }
  } catch(e) {}

  return null;
};

const getHRData = (item) => {
  let score = item.json["Điểm phù hợp"] || item.json.score || (item.json.output && item.json.output.score) || null;
  let consideration = item.json["Tóm tắt"] || item.json.consideration || (item.json.output && item.json.output.consideration) || "";
  let suitability = item.json["Sự phù hợp"] || item.json.suitability || (item.json.output && item.json.output.suitability) || "";

  if (!score && !consideration && !suitability) {
      try {
          if ($('Chuyên gia HR').isExecuted) {
              const hrJson = $('Chuyên gia HR').first().json;
              score = score || hrJson.score;
              consideration = consideration || hrJson.consideration;
              suitability = suitability || hrJson.suitability;
          }
      } catch(e) {}
  }
  return { score, consideration, suitability };
};

// MAIN PROCESS
return items.map(item => {
  const json = item.json;
  const output = json.output || {}; // Output từ AI Extract
  const hr = getHRData(item);

  // === LẤY PROFILE ===
  let profile = json.profile_wanted 
    || (output.position) 
    || findData('profile_wanted', json) 
    || findData('col_2', json)
    || "Unspecified";

  // === LẤY SOURCE DATA ===
  // Ưu tiên source_group truyền từ đầu (HO/Store/Drive)
  let source = json.source_group 
    || json.source 
    || findData('source', json) 
    || findData('col_3', json) 
    || "";

  let job_code = json.job_code || findData('job_code', json) || "";
  let position_id = json.position_id || findData('position_id', json) || "";
  let skills = json.skills || findData('skills', json) || findData('skill', json) || "N/A";

  // === LẤY FULLNAME ===
  let fullname = "Candidate";
  if (output.fullname) {
    fullname = output.fullname;
  } else if (json.fullname) {
    fullname = json.fullname;
  } else {
    try {
      if ($('Dữ liệu cá nhân').isExecuted) {
        const personalData = $('Dữ liệu cá nhân').item.json;
        if (personalData.output && personalData.output.fullname) {
          fullname = personalData.output.fullname;
        }
      }
    } catch(e) {}
  }
  if (fullname === "Candidate") {
    fullname = findData('fullname', json) || "Candidate";
  }

  // === LẤY TIME ===
  let time = json.time_create 
    || findData('time_create', json) 
    || findData('col_1', json)
    || output.timerequest 
    || new Date().toLocaleDateString('en-GB');
  time = time.toString().trim().split(" ")[0];

  const nicePosition = cleanJobTitle(profile);

  return {
    json: {
      "Điểm phù hợp": parseNumber(hr.score), 
      "Thời gian": time,
      "Vị trí ứng tuyển": nicePosition,
      "Họ và Tên": toTitleCase(fullname),
      "Số điện thoại": output.telephone || "",
      "Email": output.email || "",
      "Nơi ở": output.city || "",
      "Năm sinh": output.yearofbirth || "",
      "Giới tính": output.gender || "",
      "Bằng cấp": output["Bằng cấp"] || "",
      "Trường tốt nghiệp": output["Trường tốt nghiệp"] || "",
      "Ngành tốt nghiệp": output["Ngành tốt nghiệp"] || "",
      "Năm tốt nghiệp": output["Năm tốt nghiệp"] || "",
      "Loại tốt nghiệp": output["Loại tốt nghiệp"] || "",

      // === ÁP DỤNG CLEAN HTML ===
      "Lịch sử làm việc": cleanAndFormatList(output["Job History"] || ""),
      "Task công việc": cleanAndFormatList(output["Task công việc"] || ""),
      "Kỹ năng": cleanAndFormatList(output.Skills || ""),
      "Chứng chỉ": cleanAndFormatList(output["Certification"] || ""),
      "Tóm tắt": cleanAndFormatList(hr.consideration),
      "Sự phù hợp": cleanAndFormatList(hr.suitability),

      "Link Hồ sơ": json.link || json.webViewLink || "", // Ensure link for Drive
      "Source": source,
      "Job code": job_code,
      "Position ID": position_id,
      "Skills yêu cầu": skills,
      "profile_wanted": nicePosition,
      "fullname": toTitleCase(fullname),
      "time_create": time,
      "id": json.id,
      "name": json.name,
      // Metadata mới cho routing
      "source_group": json.source_group || (source.toLowerCase().includes('store') ? 'store' : 'ho') 
    }
  };
});

