// Gộp text từ 5 trang lại thành 1 biến duy nhất
let final_text = "";

items.forEach((item, index) => {
  const parsed = item.json.ParsedResults;
  if (parsed && parsed.length > 0) {
    final_text += `--- TRANG ${index + 1} ---\n${parsed[0].ParsedText}\n\n`;
  }
});

// Lấy item đầu tiên làm gốc (để giữ layout dữ liệu)
const firstItem = items[0] || {};
const originalData = firstItem.json || {};

// Trả về kết quả gộp + Metadata gốc (QUAN TRỌNG: Giữ lại profile_wanted, source...)
return [{
  json: {
    ...originalData,
    ocr_text_combined: final_text
  },
  // Giữ pairing với item đầu để n8n hiểu dòng chảy dữ liệu
  pairedItem: { item: 0 }
}];

// Mảng chứa kết quả đầu ra mới
const newItems = [];

// Duyệt qua từng item đầu vào
for (const item of items) {
  if (item.binary) {
    // Lấy danh sách tất cả các key file (file_0, file_1, image, ...)
    const binaryKeys = Object.keys(item.binary);

    // Duyệt qua từng file có trong item đó
    for (const key of binaryKeys) {
      // Tạo ra một item mới hoàn toàn cho mỗi file
      const newItem = {
        json: item.json, // Giữ lại thông tin JSON cũ
        binary: {
          // Đặt tên chuẩn là 'data' cho file này
          data: item.binary[key]
        }
      };
      // Đẩy item mới vào danh sách kết quả
      newItems.push(newItem);
    }
  }
}

// Trả về danh sách đã tách rời (Ví dụ: 1 item chứa 5 ảnh -> ra 5 items riêng biệt)
return newItems;

// Mảng chứa kết quả đầu ra (đã tách file)
const returnItems = [];

// Duyệt qua từng email đầu vào
// Sử dụng for loop có index để map pairing nếu cần (nhưng ta sẽ pass ID trực tiếp cho an toàn)
items.forEach((item, index) => {
  // --- PHẦN 1: TRÍCH XUẤT TEXT (Subject/Snippet) ---
  const subject = item.json.subject || item.json.Subject || "";
  const snippet = item.json.snippet || "";
  const gmailId = item.json.id; // <--- LẤY GMAIL ID

  let fullname = "Ứng viên";
  let position = "Vị trí không xác định";

  // Regex ưu tiên bắt từ Subject
  const subjectRegex = /^(.*?)\s+vừa ứng tuyển vị trí\s+(.*)$/i;
  const subjectMatch = subject.match(subjectRegex);

  if (subjectMatch) {
    fullname = subjectMatch[1].trim();
    position = subjectMatch[2].trim();
  } else {
    // Fallback tìm trong snippet
    const positionRegex = /Vị trí ứng tuyển:\s*(.*?)\s*(?:\(|\n|$)/i;
    const posMatch = snippet.match(positionRegex);
    if (posMatch) position = posMatch[1].trim();

    const nameRegex = /Họ và tên ứng viên:\s*(.*?)\s*(?:Hồ sơ:|\n|$)/i;
    const nameMatch = snippet.match(nameRegex);
    if (nameMatch) fullname = nameMatch[1].trim();
  }

  // --- PHẦN 2: TRÍCH XUẤT JOB CODE & POSITION ID ---
  let jobCode = "";
  let positionId = "";
  let source = "CareerViet"; 

  const codeRegex = /\(([^_]+)_([^)]+)\)/;
  const codeMatch = subject.match(codeRegex);

  if (codeMatch) {
    jobCode = codeMatch[1].trim();
    positionId = codeMatch[2].trim();
  }

  if (position.includes("-")) position = position.split("-")[0].trim();
  if (position.includes("(")) position = position.split("(")[0].trim();

  // --- PHẦN 3: SPLIT OUT & MERGE ---
  if (item.binary) {
    const binaryKeys = Object.keys(item.binary);

    for (const key of binaryKeys) {
      const binaryFile = item.binary[key];

      returnItems.push({
        json: {
          name: binaryFile.fileName, 
          profile_wanted: position,
          time_create: new Date().toLocaleDateString('en-GB'),
          fullname: fullname,
          source: source,
          job_code: jobCode,
          position_id: positionId,
          original_subject: subject,
          file_size_kb: Math.round(binaryFile.fileSize / 1024) + " KB",

          // --- QUAN TRỌNG: PASS GMAIL ID --- 
          gmail_id: gmailId 
        },
        binary: {
          data: binaryFile
        },
        // Map lại item gốc để n8n biết đường đi (giữ pairing)
        pairedItem: { item: index }
      });
    }
  }
});

return returnItems;

