// Lấy tất cả items từ Merge Node
const items = $input.all();

// Hàm viết hoa từng từ
const toTitleCase = (str) => {
  if (!str) return "";
  return str
    .toLowerCase()
    .split(" ")
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(" ");
};

// Làm sạch chuỗi và ép kiểu số
const parseNumber = (value) => {
  if (!value) return null;
  const cleaned = String(value)
    .replace(/[^0-9.,-]/g, "")
    .replace(",", ".");
  const num = parseFloat(cleaned);
  return isNaN(num) ? null : num;
};

// Hàm format text thành bullet list
const formatBulletList = (text) => {
  if (!text) return "";
  if (text.includes("- ") || text.includes("• ")) return text;
  const sentences = text.split(/\.\s+|\n+/).map(s => s.trim()).filter(s => s.length > 10);
  if (sentences.length <= 1) return text;
  return sentences.map(s => `• ${s}${s.endsWith('.') ? '' : '.'}`).join('\n');
};

// === LOGIC MỚI: RÚT GỌN JOB TITLE ===
const cleanJobTitle = (rawTitle) => {
  if (!rawTitle) return "Unspecified";
  // Cắt bỏ phần sau các từ khóa ngăn cách
  let clean = rawTitle.split(/[-–—_]|(\s(tại|khu vực|có|with|in|at|fmcg|kỹ năng)\s)/i)[0].trim();
  // Bỏ các ký tự lạ ở cuối
  clean = clean.replace(/[^a-zA-Z0-9àáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđ\s]+$/, "");
  return toTitleCase(clean);
};

// PARSE TỪ TÊN FILE
const parseFromFilename = (filename) => {
  if (!filename) return null;
  // Format: "DD/MM/YYYY - Position - Fullname.pdf"
  const match = filename.match(/^\d{2}\/\d{2}\/\d{4}\s*-\s*(.+?)\s*-\s*.+\.pdf$/i);
  return match ? match[1].trim() : null;
};

// Hàm lấy Source Data (UPDATED - Thêm nhiều nguồn)
const getSourceData = (item) => {
  let profile_wanted = "";
  let source = "";
  let job_code = "";
  let position_id = "";
  let skills = "";

  // 1. Thử lấy từ output AI
  if (item.json.output && item.json.output.position) profile_wanted = item.json.output.position;

  // 2. Thử lấy từ item hiện tại
  if (!profile_wanted && item.json.profile_wanted) profile_wanted = item.json.profile_wanted;
  if (item.json.source) source = item.json.source;
  if (item.json.job_code) job_code = item.json.job_code;
  if (item.json.position_id) position_id = item.json.position_id;
  if (item.json.skills) skills = item.json.skills;

  // 3. Thử lấy từ node "Code" (Drive path)
  try {
    if ($('Code').isExecuted) {
      const codeData = $('Code').first().json;
      profile_wanted = profile_wanted || codeData.col_2;
      source = source || codeData.col_3;
      job_code = job_code || codeData.job_code;
      position_id = position_id || codeData.position_id;
      skills = skills || codeData.skills;
    }
  } catch(e) {}

  // 4. Thử lấy từ upstream (Gmail)
  try {
    if ($('3. CV Parser (Split & Fix Name)').isExecuted) {
       const gmailData = $('3. CV Parser (Split & Fix Name)').item.json;
       profile_wanted = profile_wanted || gmailData.profile_wanted;
       source = source || gmailData.source;
       job_code = job_code || gmailData.job_code;
       position_id = position_id || gmailData.position_id;
    }
  } catch(e) {}

  // 5. Thử lấy từ upstream (Drive - Profile Wanted)
  try {
    if ($('Profile Wanted').isExecuted) {
       const driveData = $('Profile Wanted').first().json;
       profile_wanted = profile_wanted || driveData.profile_wanted;
       source = source || driveData.source;
       job_code = job_code || driveData.job_code;
       position_id = position_id || driveData.position_id;
       skills = skills || driveData.skill;
    }
  } catch(e) {}

  // 6. FALLBACK: Parse từ tên file
  if (!profile_wanted && item.json.name) {
    profile_wanted = parseFromFilename(item.json.name);
  }

  return { 
    profile_wanted: profile_wanted || "", 
    source: source || "",
    job_code: job_code || "",
    position_id: position_id || "",
    skills: skills || "N/A"
  };
};

// XỬ LÝ CHÍNH
const rows = items.map(item => {
  const output = item.json.output || {};
  const src = getSourceData(item);

  // 1. Xử lý Job Title (Rút gọn)
  const rawPosition = src.profile_wanted || output.position || "";
  const nicePosition = cleanJobTitle(rawPosition);

  // 2. Xử lý Tên & Thời gian
  const fullname = toTitleCase(output.fullname || item.json.fullname) || "Candidate";
  const timeCreate = item.json.time_create || output.timerequest || new Date().toLocaleDateString('en-GB');

  // 3. Xử lý Score
  const score = output.score || output.vote || null;

  return {
    json: {
      // --- FIELDS CHO GOOGLE SHEET ---
      "Điểm phù hợp": parseNumber(score),
      "Thời gian": timeCreate,
      "Vị trí ứng tuyển": nicePosition,
      "Họ và Tên": fullname,
      "Số điện thoại": output.telephone || "",
      "Email": output.email || "",
      "Nơi ở": output.city || "",
      "Năm sinh": output.yearofbirth || "",
      "Giới tính": output.gender || "",
      "Bằng cấp": output["Bằng cấp"] || "",
      "Ngành tốt nghiệp": output["Ngành tốt nghiệp"] || "",
      "Tóm tắt": formatBulletList(output.consideration || ""),
      "Sự phù hợp": formatBulletList(output.suitability || ""),
      "Link Hồ sơ": item.json.link || "",
      "Source": src.source,
      "Job code": src.job_code,
      "Position ID": src.position_id,
      "Skills yêu cầu": src.skills,

      // --- FIELDS QUAN TRỌNG CHO NODE SAU ---
      "profile_wanted": nicePosition,
      "fullname": fullname,
      "time_create": timeCreate,
      "id": item.json.id,
      "name": item.json.name
    }
  };
});

return rows;

const items = $input.all();

const toTitleCase = (str) => {
  if (!str) return "";
  return str.toLowerCase().split(" ").map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
};

const cleanJobTitle = (rawTitle) => {
  if (!rawTitle) return "Unspecified";
  let clean = rawTitle.split("(")[0];
  clean = clean.split(/[-–—_]|(\s(tại|khu vực|có|with|in|at|fmcg|kỹ năng)\s)/i)[0].trim();
  clean = clean.replace(/[^a-zA-Z0-9àáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđ\s]+$/, "");
  return toTitleCase(clean);
};

const findData = (key) => {
  try {
    if ($('Code').isExecuted) {
      const val = $('Code').first().json[key];
      if (val) return val;
    }
  } catch(e) {}

  try {
    if ($('Profile Wanted').isExecuted) {
      const val = $('Profile Wanted').first().json[key];
      if (val) return val;
    }
  } catch(e) {}

  try {
    if ($('3. CV Parser (Split & Fix Name)').isExecuted) {
      const val = $('3. CV Parser (Split & Fix Name)').item.json[key];
      if (val) return val;
    }
  } catch(e) {}

  return null;
};

return items.map(item => {
  const json = item.json;

  // === LẤY FULLNAME - ƯU TIÊN AI EXTRACTION ===
  let fullname = "Candidate";

  // 1. Ưu tiên từ AI output (Dữ liệu cá nhân)
  if (json.output && json.output.fullname) {
    fullname = json.output.fullname;
  }
  // 2. Thử tìm từ node "Dữ liệu cá nhân"
  else {
    try {
      if ($('Dữ liệu cá nhân').isExecuted) {
        const personalData = $('Dữ liệu cá nhân').item.json;
        if (personalData.output && personalData.output.fullname) {
          fullname = personalData.output.fullname;
        }
      }
    } catch(e) {}
  }

  // 3. Fallback: Lấy từ các node khác (CUỐI CÙNG)
  if (fullname === "Candidate") {
    fullname = json.fullname || findData('fullname') || "Candidate";
  }

  // === LẤY PROFILE ===
  let profile = json.profile_wanted 
    || (json.output && json.output.position) 
    || findData('profile_wanted') 
    || findData('col_2')
    || "Unspecified";

  // === LẤY TIME ===
  let time = json.time_create 
    || findData('time_create') 
    || findData('col_1')
    || new Date().toLocaleDateString('en-GB');
  time = time.toString().trim().split(" ")[0];

  // === LẤY ID ===
  let fileId = json.id;
  if (!fileId) {
    try { fileId = $('Tải CV1').item.json.id; } catch(e) {}
  }

  const shortProfile = cleanJobTitle(profile);

  return {
    json: {
      ...json,
      fullname: toTitleCase(fullname),
      profile_wanted: shortProfile,
      original_profile: profile,
      time_create: time,
      id: fileId
    }
  };
});

