// Kiểm tra response từ Compress API
const response = $input.first().json;

// Check status
if (response.code !== "200") {
  throw new Error(`Compress API failed: ${response.msg}`);
}

const fileInfo = response.data.fileInfoDTOList[0];

// Check file status
if (fileInfo.status === "failed") {
  throw new Error(`Compression failed: ${fileInfo.failureReason} (Code: ${fileInfo.failureCode})`);
}

// Check downloadUrl
if (!fileInfo.downloadUrl || fileInfo.downloadUrl === "") {
  // Nếu không có downloadUrl, dùng fileUrl (file gốc)
  console.log('⚠️ No downloadUrl, using original fileUrl');
  return [{
    json: {
      downloadUrl: fileInfo.fileUrl,
      isCompressed: false,
      originalSize: fileInfo.fileSize,
      compressedSize: fileInfo.fileSize,
      fileName: fileInfo.fileName
    }
  }];
}

// Có downloadUrl - compression thành công
return [{
  json: {
    downloadUrl: fileInfo.downloadUrl,
    isCompressed: true,
    originalSize: fileInfo.fileSize,
    compressedSize: fileInfo.convertSize,
    compressionRatio: Math.round((1 - fileInfo.convertSize / fileInfo.fileSize) * 100) + "%",
    fileName: fileInfo.downFileName || fileInfo.fileName
  }
}];
